import{_ as l,o as i,c as e,ai as r}from"./chunks/framework.CaiDwmc7.js";const g=JSON.parse('{"title":"简历排版与编写避坑指南","description":"","frontmatter":{},"headers":[],"relativePath":"resume/resume-guide.md","filePath":"resume/resume-guide.md"}'),n={name:"resume/resume-guide.md"};function t(o,a,s,h,d,u){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="简历排版与编写避坑指南" tabindex="-1">简历排版与编写避坑指南 <a class="header-anchor" href="#简历排版与编写避坑指南" aria-label="Permalink to “简历排版与编写避坑指南”">​</a></h1><hr><h3 id="💡-写在前面的话" tabindex="-1">💡 写在前面的话 <a class="header-anchor" href="#💡-写在前面的话" aria-label="Permalink to “💡 写在前面的话”">​</a></h3><p>找工作就像相亲，你的简历就是你发过去的第一张照片。HR 筛选一份简历的平均时间只有 <strong>5 秒钟</strong>！如果排版混乱、重点不突出，就算你技术再强，也会被直接扔进垃圾桶。</p><hr><h3 id="❌-简历编写的-四大死罪-绝不可犯" tabindex="-1">❌ 简历编写的“四大死罪”（绝不可犯） <a class="header-anchor" href="#❌-简历编写的-四大死罪-绝不可犯" aria-label="Permalink to “❌ 简历编写的“四大死罪”（绝不可犯）”">​</a></h3><ol><li><p><strong>废话连篇的自我评价</strong></p><ul><li>❌ 错误示范：“本人性格开朗，吃苦耐劳，具备良好的团队合作精神和沟通能力，热爱编程...”</li><li>✅ 正确做法：HR 根本不看这些。自我评价应该写<strong>硬核数据</strong>。例如：“3 年 Java 后端开发经验，精通 SpringCloud 微服务架构，有千万级用户系统的高并发调优经验。熟练掌握 JVM 排查及 MySQL 优化技巧。”</li></ul></li><li><p><strong>精通一切的“精通怪”</strong></p><ul><li>❌ 错误示范：“精通 Java、精通 MySQL、精通 Redis、精通分布式架构、精通多线程...”</li><li>⚠️ 避坑指南：面试官看到“精通”两个字，血压就上来了，必定会用最底层、最变态的源码题去疯狂考打你。</li><li>✅ 正确做法：只对你真正常握源码、极其自信的技术写“熟练掌握/深入理解”，其他的写“熟悉”或者“了解”。</li></ul></li><li><p><strong>像流水账一样的项目经历（只会写 CRUD）</strong></p><ul><li>❌ 错误示范：“项目描述：这是一个电商系统。我的职责：负责用户模块的增删改查；负责订单模块的代码编写；负责和前端联调接口。”</li><li>⚠️ 避坑指南：毫无价值！面试官看不到你的技术深度。</li><li>✅ 正确做法：必须采用 <strong>STAR 法则（情境-任务-行动-结果）</strong> 来写。在下一个章节《如何包装项目》中会详细讲解。</li></ul></li><li><p><strong>花里胡哨的排版</strong></p><ul><li>❌ 错误示范：用带背景底纹的模板，加上进度条形式的技能评分（比如 Java 画个 80% 的进度条，极其幼稚）。</li><li>✅ 正确做法：<strong>极简的黑白灰色调，单页或双页排版，纯文字列表式</strong>。推荐使用 Markdown 编写后导出为 PDF 格式发送（绝对不要发 Word，排版在别人电脑上会乱）。</li></ul></li></ol><hr><h3 id="📄-一份高分简历的标准结构" tabindex="-1">📄 一份高分简历的标准结构 <a class="header-anchor" href="#📄-一份高分简历的标准结构" aria-label="Permalink to “📄 一份高分简历的标准结构”">​</a></h3><p>一份专业的中级 Java 后端开发简历，应当严格遵循以下结构（从上到下）：</p><h4 id="_1-个人基本信息-极简" tabindex="-1">1. 个人基本信息（极简） <a class="header-anchor" href="#_1-个人基本信息-极简" aria-label="Permalink to “1. 个人基本信息（极简）”">​</a></h4><ul><li>姓名、电话、邮箱（必须）、求职意向（Java 后端开发工程师）。</li><li>（可选）博客地址、GitHub 链接（如果没有拿得出手的干货，千万别放空链接）。</li><li>年龄、学历、毕业院校（如果是统招本科及以上，一定要写明显）。</li></ul><h4 id="_2-专业技能-提炼关键词-按重要性排序" tabindex="-1">2. 专业技能（提炼关键词，按重要性排序） <a class="header-anchor" href="#_2-专业技能-提炼关键词-按重要性排序" aria-label="Permalink to “2. 专业技能（提炼关键词，按重要性排序）”">​</a></h4><p><em>这是 HR 搜索你简历时的关键词池，也是技术面试官的提纲。</em></p><ul><li><strong>示例：</strong><ul><li>熟练掌握 Java 基础，深入理解面向对象编程、集合框架、多线程并发（JUC），熟悉 JVM 内存模型与垃圾回收机制。</li><li>熟练使用 Spring、SpringBoot、SpringCloud Alibaba 微服务生态，并了解其核心源码及底层原理。</li><li>深入理解 MySQL 数据库体系架构，精通索引底层原理、事务与锁机制，具备千万级大表 SQL 慢查询调优及分库分表实战经验。</li><li>熟练掌握 Redis 核心数据结构与持久化机制，具备分布式锁、缓存雪崩/击穿/穿透防范的实战经验。</li><li>熟悉 RocketMQ 等消息队列的使用，了解消息防丢失、防重复消费及死信队列机制。</li></ul></li></ul><h4 id="_3-工作经历-倒序排列" tabindex="-1">3. 工作经历（倒序排列） <a class="header-anchor" href="#_3-工作经历-倒序排列" aria-label="Permalink to “3. 工作经历（倒序排列）”">​</a></h4><ul><li>2021.07 - 至今：某某互联网科技有限公司 —— Java 高级开发工程师</li><li>描述你在公司的核心职责、带领过多少人的小团队、负责过最核心的系统模块等。</li></ul><h4 id="_4-项目经历-全篇核心-重中之重" tabindex="-1">4. 项目经历（全篇核心，重中之重） <a class="header-anchor" href="#_4-项目经历-全篇核心-重中之重" aria-label="Permalink to “4. 项目经历（全篇核心，重中之重）”">​</a></h4><p><em>挑选最近的、含金量最高的 2-3 个项目。每个项目包含：项目名称、技术栈、项目描述、<strong>核心业绩/亮点（最重要）</strong></em>。</p><h4 id="_5-教育经历" tabindex="-1">5. 教育经历 <a class="header-anchor" href="#_5-教育经历" aria-label="Permalink to “5. 教育经历”">​</a></h4><ul><li>2017.09 - 2021.06：某某大学 —— 计算机科学与技术（本科）</li></ul><hr><h3 id="💡-投递与沟通小技巧" tabindex="-1">💡 投递与沟通小技巧 <a class="header-anchor" href="#💡-投递与沟通小技巧" aria-label="Permalink to “💡 投递与沟通小技巧”">​</a></h3><ol><li><strong>投递时机</strong>：上午 9:30-11:00，下午 14:00-16:00 是 HR 集中看简历的时间。周二、周三投递效果最好。</li><li><strong>打招呼话术</strong>：在 Boss 直聘等平台上，不要只发系统默认的打招呼。用一句话总结自己的亮点发过去。 <ul><li>例如：“您好！我是具有 3 年经验的 Java 工程师，曾在前司主导过千万级订单系统的微服务拆分和重构，精通 MySQL 调优，看过贵司 JD 非常匹配，期待沟通！”（这种转化率极高）。</li></ul></li></ol>',24)])])}const p=l(n,[["render",t]]);export{g as __pageData,p as default};
